class HomeScreen extends StatefulWidget {
  const HomeScreen({super.key});

  @override
  State<HomeScreen> createState() => _HomeScreenState();
}

class _HomeScreenState extends State<HomeScreen> {
  String? _authMethod;
  bool _biometricEnabled = false;
  final BiometricService _biometricService = BiometricService();

  @override
  void initState() {
    super.initState();
    _loadAuthInfo();
  }

  Future<void> _loadAuthInfo() async {
    final method = await AuthPreferences.getAuthMethod();
    final biometricAvailable = await _biometricService.isBiometricAvailable();

    setState(() {
      _authMethod = method;
      _biometricEnabled = method == 'biometric' && biometricAvailable;
    });
  }

  Future<void> _toggleBiometric(bool enable) async {
    if (enable) {
      final authenticated = await _biometricService.authenticate();
      if (authenticated) {
        await AuthPreferences.setAuthMethod('biometric');
        setState(() {
          _biometricEnabled = true;
          _authMethod = 'biometric';
        });
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text('Biometric authentication enabled!'),
              backgroundColor: Colors.green,
            ),
          );
        }
      }
    } else {
      await AuthPreferences.setAuthMethod('password');
      setState(() {
        _biometricEnabled = false;
        _authMethod = 'password';
      });
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(
            content: Text('Biometric authentication disabled.'),
          ),
        );
      }
    }
  }

  Future<void> _logout() async {
    final confirmed = await showDialog<bool>(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('Logout'),
        content: const Text('Are you sure you want to logout?'),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(context, false),
            child: const Text('Cancel'),
          ),
          FilledButton(
            onPressed: () => Navigator.pop(context, true),
            child: const Text('Logout'),
          ),
        ],
      ),
    );

    if (confirmed == true) {
      await AuthPreferences.clearAuth();
      if (mounted) {
        Navigator.of(context).pushReplacement(
          MaterialPageRoute(builder: (_) => const LoginScreen()),
        );
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Home'),
        centerTitle: true,
        actions: [
          IconButton(
            icon: const Icon(Icons.logout),
            onPressed: _logout,
            tooltip: 'Logout',
          ),
        ],
      ),
      body: Padding(
        padding: const EdgeInsets.all(24.0),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            Card(
              elevation: 0,
              color: Theme.of(context).colorScheme.primaryContainer,
              child: Padding(
                padding: const EdgeInsets.all(24.0),
                child: Column(
                  children: [
                    Icon(
                      Icons.check_circle,
                      size: 64,
                      color: Theme.of(context).colorScheme.primary,
                    ),
                    const SizedBox(height: 16),
                    Text(
                      'Authentication Successful!',
                      style: Theme.of(context).textTheme.titleLarge?.copyWith(
                            fontWeight: FontWeight.bold,
                          ),
                    ),
                    const SizedBox(height: 8),
                    Text(
                      'Authenticated via: ${_authMethod ?? 'Unknown'}',
                      style: Theme.of(context).textTheme.bodyMedium?.copyWith(
                            color: Colors.grey[600],
                          ),
                    ),
                  ],
                ),
              ),
            ),
            const SizedBox(height: 24),
            Card(
              elevation: 0,
              shape: RoundedRectangleBorder(
                borderRadius: BorderRadius.circular(12),
                side: BorderSide(color: Colors.grey[300]!),
              ),
              child: Column(
                children: [
                  ListTile(
                    leading: const Icon(Icons.fingerprint),
                    title: const Text('Biometric Login'),
                    subtitle: const Text('Use fingerprint or Face ID to login'),
                    trailing: FutureBuilder<bool>(
                      future: _biometricService.isBiometricAvailable(),
                      builder: (context, snapshot) {
                        if (!snapshot.hasData || !snapshot.data!) {
                          return const Chip(label: Text('Unavailable'));
                        }
                        return Switch(
                          value: _biometricEnabled,
                          onChanged: _toggleBiometric,
                        );
                      },
                    ),
                  ),
                  const Divider(height: 1),
                  ListTile(
                    leading: const Icon(Icons.security),
                    title: const Text('Security Status'),
                    subtitle: Text(
                      _biometricEnabled
                          ? 'Enhanced security with biometrics'
                          : 'Standard password protection',
                    ),
                    trailing: Icon(
                      _biometricEnabled ? Icons.shield : Icons.shield_outlined,
                      color: _biometricEnabled ? Colors.green : Colors.grey,
                    ),
                  ),
                  const Divider(height: 1),
                  FutureBuilder<List<BiometricType>>(
                    future: _biometricService.getAvailableBiometrics(),
                    builder: (context, snapshot) {
                      final biometrics = snapshot.data ?? [];
                      return ListTile(
                        leading: const Icon(Icons.devices),
                        title: const Text('Available Biometrics'),
                        subtitle: Text(
                          biometrics.isEmpty
                              ? 'None'
                              : biometrics
                                  .map((b) => b.name[0].toUpperCase() + b.name.substring(1))
                                  .join(', '),
                        ),
                      );
                    },
                  ),
                ],
              ),
            ),
            const Spacer(),
            OutlinedButton.icon(
              onPressed: _logout,
              icon: const Icon(Icons.logout),
              label: const Text('Sign Out'),
              style: OutlinedButton.styleFrom(
                padding: const EdgeInsets.symmetric(vertical: 16),
                foregroundColor: Colors.red,
                side: const BorderSide(color: Colors.red),
                shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(12),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }
}